glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uSeed;
uniform vec3 baseColor;
uniform vec3 warmColor;
uniform vec3 coolColor;
uniform vec3 accentColor;
uniform float axisWidth;
uniform float grain;
float hash(vec2 p){return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453123);}
float noise(vec2 p){
 vec2 i=floor(p), f=fract(p);
 float a=hash(i), b=hash(i+vec2(1.,0.)), c=hash(i+vec2(0.,1.)), d=hash(i+vec2(1.,1.));
 vec2 u=f*f*(3.0-2.0*f);
 return mix(a,b,u.x)+(c-a)*u.y*(1.0-u.x)+(d-b)*u.x*u.y;
}
void main(){
 vec2 uv=vUv;
 float x=uv.x-0.5;
 float axis=smoothstep(axisWidth, axisWidth*0.35, abs(x));
 float leftPanel=smoothstep(0.36,0.18,abs(uv.x-0.22));
 float rightPanel=smoothstep(0.36,0.18,abs(uv.x-0.78));
 float warmBand=smoothstep(0.0,1.0,1.0-abs(uv.y-0.58)*1.6)*(0.55+0.45*leftPanel);
 float coolBand=smoothstep(0.0,1.0,1.0-abs(uv.y-0.44)*1.8)*(0.55+0.45*rightPanel);
 float verticalPulse=0.5+0.5*sin((uv.y*8.0+uSeed)*3.14159);
 float grainMask=(noise(uv*vec2(220.0,160.0)+uSeed)-0.5)*grain;
 vec3 col=baseColor;
 col=mix(col,warmColor,0.18*warmBand);
 col=mix(col,coolColor,0.14*coolBand);
 col=mix(col,accentColor,0.22*axis*verticalPulse);
 col += grainMask*0.08;
 float alpha=0.96;
 gl_FragColor=vec4(col,alpha);
}

