glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uSeed;
uniform vec3 anchorColor;
uniform vec3 glowColor;
uniform vec3 outerColor;
uniform float thickness;
uniform float elongation;
float sdEllipse(vec2 p, vec2 r){
 return length(p/r)-1.0;
}
void main(){
 vec2 uv=vUv*2.0-1.0;
 uv.y*=elongation;
 vec2 p1=uv+vec2(0.22,0.0);
 vec2 p2=uv-vec2(0.22,0.0);
 float e1=sdEllipse(p1, vec2(0.62,0.82));
 float e2=sdEllipse(p2, vec2(0.62,0.82));
 float mand=max(e1,e2);
 float ring=smoothstep(thickness, 0.0, abs(mand));
 float core=smoothstep(0.22, -0.02, mand);
 float innerPulse=0.86+0.14*sin(uSeed*6.2831+uv.y*3.0);
 vec3 col=mix(glowColor, anchorColor, core);
 col=mix(col, outerColor, ring*0.35);
 col += glowColor * ring * 0.22 * innerPulse;
 float alpha=max(ring*0.9, core*0.78);
 alpha*=smoothstep(1.22,0.96,length(uv));
 gl_FragColor=vec4(col, alpha);
}

