glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uSeed;
uniform vec3 barColor;
uniform vec3 markColor;
uniform float count;
float box(vec2 p, vec2 b){
 vec2 d=abs(p)-b;
 return max(d.x,d.y);
}
void main(){
 vec2 uv=vUv*2.0-1.0;
 float alpha=0.0;
 vec3 col=vec3(0.0);
 for(int i=0;i<12;i++){
 if(float(i)>=count) break;
 float fi=float(i);
 float y=-0.72+fi*0.24;
 float width=0.16+fi*0.045;
 float x=-0.42+fi*0.11;
 float d=box(uv-vec2(x,y), vec2(width,0.028));
 float bar=smoothstep(0.035,0.0,d);
 col += mix(barColor, markColor, fi/max(count-1.0,1.0))*bar;
 alpha += bar*0.85;
 }
 alpha=clamp(alpha,0.0,1.0);
 gl_FragColor=vec4(col, alpha);
}
